3027:     private int getImpliedSystemUiVisibility(WindowManager.LayoutParams params) {
3028:         int vis = 0;
3029:         // Translucent decor window flags imply stable system ui visibility.
3030:         if ((params.flags & FLAG_TRANSLUCENT_STATUS) != 0) {
3031:             vis |= View.SYSTEM_UI_FLAG_LAYOUT_STABLE | View.SYSTEM_UI_FLAG_LAYOUT_FULLSCREEN;
3032:         }
3033:         if ((params.flags & FLAG_TRANSLUCENT_NAVIGATION) != 0) {
3034:             vis |= View.SYSTEM_UI_FLAG_LAYOUT_STABLE | View.SYSTEM_UI_FLAG_LAYOUT_HIDE_NAVIGATION;
3035:         }
3036:         return vis;
