3042:     void updateCompatSysUiVisibility(@InsetsType int visibleTypes,
3043:             @InsetsType int requestedVisibleTypes, @InsetsType int controllableTypes) {
3044:         // If a type is controllable, the visibility is overridden by the requested visibility.
3045:         visibleTypes =
