3055:     private void updateCompatSystemUiVisibilityInfo(int systemUiFlag, @InsetsType int insetsType,
3056:             @InsetsType int visibleTypes, @InsetsType int controllableTypes) {
3057:         final SystemUiVisibilityInfo info = mCompatibleVisibilityInfo;
3058:         final boolean willBeVisible = (visibleTypes & insetsType) != 0;
3059:         final boolean hasControl = (controllableTypes & insetsType) != 0;
3060:         final boolean wasInvisible = (mAttachInfo.mSystemUiVisibility & systemUiFlag) != 0;
3061:         if (willBeVisible) {
3062:             info.globalVisibility &= ~systemUiFlag;
3063:             if (hasControl && wasInvisible) {
3064:                 // The local system UI visibility can only be cleared while we have the control.
3065:                 info.localChanges |= systemUiFlag;
3066:             }
3067:         } else {
3068:             info.globalVisibility |= systemUiFlag;
3069:             info.localChanges &= ~systemUiFlag;
3070:         }
3071:     }
